SELECT forecast_id, COUNT(access_id) AS access_count
FROM forecast_access
GROUP BY forecast_id;

SELECT user_id, action
FROM forecast_access
WHERE forecast_id = 0 AND access_type = 'edit';

SELECT model_id, AVG(accuracy) as average_accuracy
FROM sales_models
GROUP BY model_id;

SELECT COUNT(*) 
FROM forecast_access
WHERE user_id = 0;

SELECT forecast_value
FROM sales_forecasts
WHERE forecast_id = 0;

SELECT MAX(update_date) AS latest_update_date
FROM model_updates
WHERE model_id = 0;

SELECT model_name
FROM sales_models
WHERE accuracy > 80.0;

SELECT target_value
FROM forecast_targets
WHERE status = 'active';

SELECT COUNT(*) 
FROM forecast_targets 
WHERE status = 'active';
